#include "mlx90640.h"
#include <Wire.h>
#include <MLX90640_API.h>
#include <MLX90640_I2C_Driver.h>
static float _frame[768];
static float _maxT=0;
static unsigned long _last=0;
static paramsMLX90640 _params;
static uint16_t _eeData[832];
void mlx90640_setup(){
  Wire.begin();Wire.setClock(400000);
  int st=MLX90640_DumpEE(0x33,_eeData);
  if(st!=0){Serial.println("[mlx90640] EE dump failed");return;}
  MLX90640_ExtractParameters(_eeData,&_params);
  Serial.println("[mlx90640] OK 32x24");
}
void mlx90640_loop(){
  if(millis()-_last<500)return;
  _last=millis();
  uint16_t sub[834];
  MLX90640_GetFrameData(0x33,sub);
  float ta=MLX90640_GetTa(sub,&_params);
  MLX90640_CalculateTo(sub,&_params,0.95,ta-8,_frame);
  _maxT=_frame[0];for(int i=1;i<768;i++)if(_frame[i]>_maxT)_maxT=_frame[i];
}
float mlx90640_get_pixel(int i){return(i>=0&&i<768)?_frame[i]:0;}
float mlx90640_get_max_temp(){return _maxT;}
